import{_ as o,C as s,o as l,c as r,ag as t,E as i}from"./chunks/framework._658-eYr.js";const k=JSON.parse('{"title":"AI Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-providers.md","filePath":"guide/ai-providers.md"}'),n={name:"guide/ai-providers.md"};function d(p,e,c,h,u,m){const a=s("SchemeImage");return l(),r("div",null,[e[0]||(e[0]=t(`<h1 id="ai-providers" tabindex="-1">AI Providers <a class="header-anchor" href="#ai-providers" aria-label="Permalink to &quot;AI Providers&quot;">​</a></h1><p>CRAFT supports three AI providers. All can be active simultaneously — choose per-request from the model dropdown.</p><h2 id="gemini-google" tabindex="-1">Gemini (Google) <a class="header-anchor" href="#gemini-google" aria-label="Permalink to &quot;Gemini (Google)&quot;">​</a></h2><p><strong>Setup</strong>: Add <code>GEMINI_API_KEY</code> to <code>app/.env</code></p><p>Get a key at <a href="https://ai.google.dev/gemini-api/docs/api-key" target="_blank" rel="noreferrer">ai.google.dev</a>.</p><p><strong>Models available</strong>: gemini-1.5-flash, gemini-1.5-pro, gemini-2.0-flash, and newer</p><p><strong>Characteristics</strong>:</p><ul><li>Streams responses token-by-token (real-time)</li><li>Reliable with standard API keys</li><li>Good for quick iterations</li></ul><h2 id="claude-anthropic" tabindex="-1">Claude (Anthropic) <a class="header-anchor" href="#claude-anthropic" aria-label="Permalink to &quot;Claude (Anthropic)&quot;">​</a></h2><p><strong>Setup</strong>: Claude uses the <a href="https://platform.claude.com/docs/en/agent-sdk/typescript" target="_blank" rel="noreferrer">Agent SDK</a> which authenticates via your <strong>Claude Pro subscription</strong> (OAuth), not a separate API key.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ol><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> installed and logged in on your machine</li><li>OAuth credentials at <code>~/.claude/.credentials.json</code> (created automatically by Claude Code login)</li></ol><div class="warning custom-block"><p class="custom-block-title">No API Credits Needed</p><p>Unlike the raw Anthropic API, the Agent SDK uses your Pro subscription. The <code>ANTHROPIC_API_KEY</code> in <code>.env</code> is intentionally cleared in Docker so the SDK falls back to OAuth.</p></div><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your machine (~/.claude/) ──mount──→ Docker container</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>                    Agent SDK spawns Claude Code CLI</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>                    CLI authenticates via OAuth (Pro)</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>                    MCP servers available (storytelling, comedy, etc.)</span></span></code></pre></div><p><strong>Models available</strong>: claude-sonnet-4-6, claude-opus-4-6, claude-haiku-4-5, and older</p><p><strong>Characteristics</strong>:</p><ul><li>Responses arrive as a single block (not streamed) — the SDK filters out MCP planning text</li><li>May use MCP research tools for richer responses (especially Opus)</li><li>Excellent for complex script writing and fact-checking</li></ul><h2 id="ollama-local-llm" tabindex="-1">Ollama (Local LLM) <a class="header-anchor" href="#ollama-local-llm" aria-label="Permalink to &quot;Ollama (Local LLM)&quot;">​</a></h2><p><strong>Setup</strong>: Enable GPU services in your deployment.</p><p><strong>Helm</strong>: Set <code>gpu.enabled: true</code> and <code>gpu.runtime: nvidia</code> (or <code>rocm</code>) in <code>values-dev.yaml</code>, then upgrade:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">helm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> craft</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./helm/craft</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> helm/craft/values-dev.yaml</span></span></code></pre></div><p>Check the Ollama pod is running: <code>kubectl get pods -l app.kubernetes.io/component=ollama</code></p><p><strong>Docker Compose (local dev)</strong>: <code>docker compose -f docker-compose.dev.yml --profile gpu up -d</code></p><p>No API key needed — models run entirely on your local GPU.</p><p><strong>How to pull models</strong>:</p><ol><li>Open <strong>Settings</strong> (gear icon on any channel)</li><li>Scroll to <strong>Local AI (Ollama)</strong> section</li><li>Click a suggested model chip (Qwen 2.5 Coder 14B or DeepSeek R1 14B)</li><li>Or type any model name (e.g. <code>llama3.1:8b</code>) and click <strong>Pull</strong></li><li>Progress shows in real-time; models persist across restarts in <code>./models/ollama/</code></li></ol><p><strong>Suggested models</strong>:</p><table tabindex="0"><thead><tr><th>Model</th><th>Size</th><th>Best For</th></tr></thead><tbody><tr><td><code>qwen2.5-coder:14b</code></td><td>~9 GB</td><td>Script writing, code-aware content</td></tr><tr><td><code>deepseek-r1:14b</code></td><td>~9 GB</td><td>Reasoning, fact-heavy scripts</td></tr><tr><td><code>llama3.1:8b</code></td><td>~5 GB</td><td>General purpose (lower VRAM)</td></tr></tbody></table><p><strong>Characteristics</strong>:</p><ul><li>Streams responses token-by-token (like Gemini)</li><li>Fully offline — no internet needed after model download</li><li>GPU required for usable speed (CPU inference is very slow)</li><li>Models can be pulled and deleted from the Settings panel</li></ul><div class="tip custom-block"><p class="custom-block-title">VRAM Requirements</p><p>14B parameter models need ~10 GB VRAM. If you have 8 GB or less, use 7B/8B variants instead.</p></div>`,32)),i(a,{name:"ollama-models",alt:"Ollama model management in Settings"}),e[1]||(e[1]=t('<h2 id="model-selection" tabindex="-1">Model Selection <a class="header-anchor" href="#model-selection" aria-label="Permalink to &quot;Model Selection&quot;">​</a></h2><p>The model dropdown appears in:</p><ul><li>Script Editor AI toolbar</li><li>AI Chat panel</li><li>Idea generation modal</li><li>Mobile app script detail</li></ul><p>All three providers show in the same dropdown when configured, grouped by provider (Claude, Gemini, Ollama). Disabled providers show a reason (e.g., &quot;No API credits&quot;, &quot;Service error&quot;).</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Gemini</th><th>Claude</th><th>Ollama</th></tr></thead><tbody><tr><td>Auth</td><td>API key</td><td>OAuth (Pro subscription)</td><td>None (local)</td></tr><tr><td>Streaming</td><td>Yes (token-by-token)</td><td>No (buffered response)</td><td>Yes (token-by-token)</td></tr><tr><td>MCP Tools</td><td>No</td><td>Yes (storytelling, comedy, etc.)</td><td>No</td></tr><tr><td>Speed</td><td>Fast</td><td>Slower (multi-turn possible)</td><td>Depends on GPU</td></tr><tr><td>Cost</td><td>API credits</td><td>Included in Pro</td><td>Free (your hardware)</td></tr><tr><td>Internet</td><td>Required</td><td>Required</td><td>Not needed (after model pull)</td></tr></tbody></table>',6))])}const b=o(n,[["render",d]]);export{k as __pageData,b as default};
